import{_ as o,o as r,c as e,a3 as a}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"🤖 LLM 对话 — 快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/index.md","filePath":"user-guide/tools/llm-chat/index.md","lastUpdated":1778233540000}'),l={name:"user-guide/tools/llm-chat/index.md"};function s(n,t,d,i,g,c){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="🤖-llm-对话-—-快速上手" tabindex="-1">🤖 LLM 对话 — 快速上手 <a class="header-anchor" href="#🤖-llm-对话-—-快速上手" aria-label="Permalink to &quot;🤖 LLM 对话 — 快速上手&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">功能概要</p><p>LLM 对话是 AIO Hub 中最核心、功能最丰富的工具。它不仅仅是聊天窗口，更是一个支持<strong>树状分支对话</strong>、<strong>智能体 (Agent) 系统</strong>、<strong>世界书 (Worldbook)</strong>、<strong>上下文管道</strong>等高级功能的综合对话引擎。</p></div><h2 id="核心特性一览" tabindex="-1">核心特性一览 <a class="header-anchor" href="#核心特性一览" aria-label="Permalink to &quot;核心特性一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>说明</th></tr></thead><tbody><tr><td>🧬 树状分支</td><td>每条消息都可以产生多个回复分支，自由切换和对比</td></tr><tr><td>🤖 智能体系统</td><td>预设角色、系统提示词、模型参数，一键切换不同 Agent</td></tr><tr><td>📖 世界书</td><td>类似角色扮演游戏的背景设定库，自动匹配关键词注入上下文</td></tr><tr><td>🔧 上下文管道</td><td>可编排的上下文处理器链，灵活控制发送给 LLM 的内容</td></tr><tr><td>📎 附件管理</td><td>支持图片、文件、音频等附件，无缝集成资产管理器</td></tr><tr><td>📤 导入导出</td><td>支持 JSON / Markdown 导出，跨设备迁移数据</td></tr></tbody></table><h2 id="开始第一次对话" tabindex="-1">开始第一次对话 <a class="header-anchor" href="#开始第一次对话" aria-label="Permalink to &quot;开始第一次对话&quot;">​</a></h2><ol><li><strong>打开 LLM 对话工具</strong>：从 <strong>🏠 主页</strong> 的工具网格中点击 <strong>💬 LLM 聊天</strong> 卡片。打开后，它会出现在左侧侧边栏的标签列表中。</li><li><strong>确认已配置 AI 服务</strong>：如果尚未配置，请先点击窗口右上角的 <strong>⚙️ 设置</strong> 图标，前往「AI 服务配置」添加 API Key。</li><li><strong>选择或创建 Agent</strong>：首次使用会自动创建默认的「助手」Agent，你也可以从智能体面板新建</li><li><strong>在输入框打字</strong>：底部的消息输入框支持多行文本，按 <code>Ctrl + Enter</code> 发送（可在设置中改为 <code>Enter</code>）</li></ol><blockquote><p>TODO: 截图 — 首次打开 LLM Chat 的界面布局，标注三栏区域</p></blockquote><h2 id="界面布局速览" tabindex="-1">界面布局速览 <a class="header-anchor" href="#界面布局速览" aria-label="Permalink to &quot;界面布局速览&quot;">​</a></h2><p>LLM 对话采用经典的三栏布局：</p><ul><li><strong>左栏</strong>：功能切换区。通过顶部标签页在 <strong>🔮 智能体列表</strong> 和 <strong>⚙️ 模型参数</strong> 之间切换。</li><li><strong>中栏</strong>：核心对话区。包括消息展示区域（线性列表或树状图）和底部的消息输入框。</li><li><strong>右栏</strong>：会话管理区。列出所有历史会话，支持搜索、重命名和删除。</li></ul><p>顶部标题栏支持<strong>拖拽分离</strong>，将对话区域独立成浮动窗口。</p><blockquote><p>TODO: 截图 — 标注左/中/右三栏说明</p></blockquote><h2 id="快速技巧" tabindex="-1">快速技巧 <a class="header-anchor" href="#快速技巧" aria-label="Permalink to &quot;快速技巧&quot;">​</a></h2><ul><li><strong>切换视图</strong>：点击中栏顶部的按钮可在「线性消息列表」和「对话树图」间切换</li><li><strong>上下文分析器</strong>：点击工具栏的 🔍 按钮查看即将发送给 LLM 的完整上下文</li><li><strong>快捷键</strong>：<code>Ctrl + Enter</code> 发送、<code>Ctrl + Z</code> 撤销、<code>Ctrl + Shift + Z</code> 重做</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./sessions">会话管理</a> — 管理你的多个对话会话</li><li><a href="./messages">消息操作</a> — 编辑、重发、删除消息</li><li><a href="./agents">智能体</a> — 配置角色预设和高级参数</li><li><a href="./settings-chat">聊天参数</a> — 温度、Top-P、Token 上限等模型参数调优</li></ul>',16)])])}const p=o(l,[["render",s]]);export{u as __pageData,p as default};
